// Phase 2 — AI-generated Shortcut endpoint
//
// POST /api/ios/build-shortcut
//   Body: { title: String, dsl: String }
//   Response 200: { url: String }
//   Response 4xx/5xx: { error: String }
//
// Flow:
//   1. Receive Cherri DSL from iOS app (generated by Apple FM on-device)
//   2. Write DSL to a temp file on the harness machine
//   3. SCP the DSL to the configured Mac signing host
//   4. SSH the Mac: run `cherri /tmp/<id>.cherri -s anyone`
//   5. Cherri uses Shortcuts CLI on Mac (or HubSign fallback) to sign
//   6. SCP signed .shortcut back to harness
//   7. Host the signed file at /api/ios/build-shortcut/<id>.shortcut
//      with a 5-minute TTL
//   8. Return the URL to iOS
//
// Mac signing config via env vars (set in harness config.json or env):
//   HARNESS_MAC_SIGN_HOST   — SSH hostname (e.g. user@FF125.macincloud.com)
//   HARNESS_MAC_SIGN_TMPDIR — temp dir on Mac (default: /tmp)
//   HARNESS_MAC_CHERRI_BIN  — path to cherri on Mac (default: ~/bin/cherri)
//
// Authentication: same Bearer middleware as other ios-router endpoints.

import { spawn } from 'node:child_process';
import { promises as fs } from 'node:fs';
import path from 'node:path';
import os from 'node:os';
import crypto from 'node:crypto';
import { log } from '../logger.js';

const logger = {
  info: (msg, meta) => log(`[build-shortcut] ${msg}`, meta || ''),
  warn: (msg, meta) => log(`[build-shortcut][warn] ${msg}`, meta || ''),
  error: (msg, meta) => log(`[build-shortcut][error] ${msg}`, meta || ''),
};

// MARK: - In-memory hosted files (TTL 5 min)

/**
 * Map of <id> → { filePath: String, expiresAt: Date }
 * Used to serve the signed .shortcut file after build. Auto-pruned on every
 * GET to keep memory bounded.
 */
const hostedFiles = new Map();
const FILE_TTL_MS = 5 * 60 * 1000;  // 5 minutes

function pruneExpired() {
  const now = Date.now();
  for (const [id, entry] of hostedFiles.entries()) {
    if (entry.expiresAt < now) {
      hostedFiles.delete(id);
      fs.unlink(entry.filePath).catch(() => {});
    }
  }
}

// MARK: - Config

function macSignHost() {
  return process.env.HARNESS_MAC_SIGN_HOST || '';
}

function macTmpDir() {
  return process.env.HARNESS_MAC_SIGN_TMPDIR || '/tmp';
}

function macCherriBin() {
  return process.env.HARNESS_MAC_CHERRI_BIN || '~/bin/cherri';
}

// MARK: - Shell helpers

/**
 * Run a command, return stdout (Buffer). Rejects with stderr on non-zero
 * exit. Times out after 30s by default (cherri compile + signing typically
 * 2-8 seconds).
 */
function runCommand(cmd, args, timeoutMs = 30000) {
  return new Promise((resolve, reject) => {
    const child = spawn(cmd, args, { stdio: ['ignore', 'pipe', 'pipe'] });
    const out = [];
    const err = [];
    child.stdout.on('data', (chunk) => out.push(chunk));
    child.stderr.on('data', (chunk) => err.push(chunk));

    const timer = setTimeout(() => {
      child.kill('SIGKILL');
      reject(new Error(`Command timed out: ${cmd} ${args.join(' ')}`));
    }, timeoutMs);

    child.on('exit', (code) => {
      clearTimeout(timer);
      if (code === 0) {
        resolve(Buffer.concat(out));
      } else {
        const stderrText = Buffer.concat(err).toString('utf8');
        reject(new Error(`Command failed (exit ${code}): ${stderrText.slice(0, 500)}`));
      }
    });

    child.on('error', (e) => {
      clearTimeout(timer);
      reject(e);
    });
  });
}

// MARK: - Compile + sign pipeline

/**
 * Compiles + signs the given Cherri DSL on the configured Mac.
 * Returns Buffer of the signed .shortcut file bytes.
 *
 * Strategy:
 *   1. Write DSL to local tmp file
 *   2. scp DSL to Mac at ${macTmpDir()}/<id>.cherri
 *   3. ssh Mac: ${macCherriBin()} <path>.cherri -s anyone
 *      → produces sibling <path>.shortcut on Mac
 *   4. scp .shortcut back from Mac to local
 *   5. Return Buffer
 *
 * Each step's failure surfaces as Error → caller turns into 5xx response.
 */
async function compileAndSignOnMac(id, dsl) {
  const host = macSignHost();
  if (!host) {
    throw new Error('HARNESS_MAC_SIGN_HOST not configured. Set it to user@your.mac.example to enable AI-generated Shortcuts.');
  }

  const localDir = path.join(os.tmpdir(), 'gigi-shortcuts');
  await fs.mkdir(localDir, { recursive: true });
  const localDsl = path.join(localDir, `${id}.cherri`);
  const localShortcut = path.join(localDir, `${id}.shortcut`);
  const macDsl = `${macTmpDir()}/${id}.cherri`;
  const macShortcut = `${macTmpDir()}/${id}.shortcut`;

  logger.info(`compiling ${id} — DSL ${dsl.length} bytes`);

  // 1. local DSL file
  await fs.writeFile(localDsl, dsl, 'utf8');

  // 2. SCP to Mac
  await runCommand('scp', ['-o', 'StrictHostKeyChecking=accept-new', localDsl, `${host}:${macDsl}`]);

  // 3. SSH compile + sign
  const cherriCmd = `${macCherriBin()} ${macDsl} -s anyone 2>&1`;
  await runCommand('ssh', ['-o', 'StrictHostKeyChecking=accept-new', host, cherriCmd]);

  // 4. SCP signed file back
  await runCommand('scp', ['-o', 'StrictHostKeyChecking=accept-new', `${host}:${macShortcut}`, localShortcut]);

  // Clean up Mac tmp
  runCommand('ssh', ['-o', 'StrictHostKeyChecking=accept-new', host, `rm -f ${macDsl} ${macShortcut}`])
    .catch((e) => logger.warn(`mac cleanup failed: ${e.message}`));

  // 5. Read bytes
  const buf = await fs.readFile(localShortcut);
  logger.info(`compiled ${id} — signed ${buf.length} bytes`);
  return { path: localShortcut, bytes: buf };
}

// MARK: - Endpoint handlers

export async function handleBuildShortcut(req, res, ctx) {
  // Drain body (the router has already done some, but keep robust).
  let raw = '';
  for await (const chunk of req) raw += chunk;

  let payload;
  try {
    payload = JSON.parse(raw);
  } catch (e) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
    return;
  }

  const title = String(payload.title || 'GIGI Shortcut').slice(0, 80);
  const dsl = String(payload.dsl || '').trim();
  if (!dsl) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Missing DSL' }));
    return;
  }
  if (dsl.length > 100_000) {
    res.writeHead(413, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'DSL too large (max 100 KB)' }));
    return;
  }

  const id = crypto.randomBytes(8).toString('hex');

  try {
    const compiled = await compileAndSignOnMac(id, dsl);
    hostedFiles.set(id, {
      filePath: compiled.path,
      title,
      expiresAt: Date.now() + FILE_TTL_MS
    });

    // Build the public URL using the harness public base URL if configured,
    // else fall back to the request Host header.
    const baseURL = ctx.cfg?.publicBaseURL
      || `http://${req.headers.host || 'localhost:7779'}`;
    const url = `${baseURL.replace(/\/$/, '')}/api/ios/build-shortcut/${id}.shortcut`;

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true, url, id, title }));
  } catch (e) {
    logger.error(`compile failed: ${e.message}`);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: `Compile failed: ${e.message}` }));
  }
}

/**
 * Serves the signed .shortcut file. Triggered by iOS UIApplication.open
 * when the iOS app received the URL from /build-shortcut POST.
 *
 * Path format: /api/ios/build-shortcut/<id>.shortcut
 */
export async function handleShortcutFile(req, res, _ctx) {
  pruneExpired();

  const url = new URL(req.url, `http://${req.headers.host}`);
  const m = url.pathname.match(/^\/api\/ios\/build-shortcut\/([a-f0-9]+)\.shortcut$/);
  if (!m) {
    res.writeHead(404);
    res.end();
    return;
  }
  const id = m[1];
  const entry = hostedFiles.get(id);
  if (!entry || entry.expiresAt < Date.now()) {
    res.writeHead(410);  // Gone — file expired
    res.end();
    return;
  }

  let bytes;
  try {
    bytes = await fs.readFile(entry.filePath);
  } catch (e) {
    res.writeHead(500);
    res.end();
    return;
  }

  const niceName = entry.title.replace(/[^\w\s-]/g, '').replace(/\s+/g, '-').slice(0, 40) || 'GIGI-Shortcut';
  res.writeHead(200, {
    'Content-Type': 'application/x-apple-aspen-config',
    'Content-Disposition': `inline; filename="${niceName}.shortcut"`,
    'Cache-Control': 'no-store, no-cache, must-revalidate',
    'Content-Length': bytes.length
  });
  res.end(bytes);
}
